const reactedTs = $('Slack Trigger').first().json.item.ts;
const messages = $json.messages || [];

// conversations.history returns newest-first. The reacted message and any earlier bot draft are in here.
const stripFooter = (t) => (t || '').replace(/_\[phaedon-bot\]_\s*$/, '').replace(/\[phaedon-bot\]\s*$/i, '').trim();

// Find the message the user reacted to.
const reactedMsg = messages.find(m => m.ts === reactedTs);

// All bot drafts (real APP-posted messages, not the human echo). Exclude approval confirmations.
// A real bot draft has bot_id set; a human paste of '[phaedon-bot]' won't.
const botDrafts = messages.filter(m => m.bot_id && m.text && m.text.includes('[phaedon-bot]') && !m.text.startsWith('Approved and queued'));

// The most recent bot draft AT OR BEFORE the reacted message — this is what's in Notion.
const reactedTsNum = parseFloat(reactedTs);
const priorBotDrafts = botDrafts.filter(m => parseFloat(m.ts) <= reactedTsNum);
priorBotDrafts.sort((a, b) => parseFloat(b.ts) - parseFloat(a.ts));
const botDraft = priorBotDrafts[0] || botDrafts.sort((a, b) => parseFloat(b.ts) - parseFloat(a.ts))[0] || null;

// Final text: if the user reacted on a non-bot message (their edited copy), use that. Otherwise use the bot draft.
let finalText = '';
if (reactedMsg && !reactedMsg.bot_id) {
  finalText = stripFooter(reactedMsg.text);
} else if (botDraft) {
  finalText = stripFooter(botDraft.text);
}

// Candidate TS list for Notion lookup, in priority order:
//   1. The bot draft's ts (this is what was stored when staging).
//   2. The reacted message's ts (in case Notion was somehow staged with that).
const candidateTsList = [botDraft ? botDraft.ts : '', reactedTs].filter(Boolean);
const candidateTs = [...new Set(candidateTsList)].join(',');

return {
  bot_ts: botDraft ? botDraft.ts : reactedTs,
  candidate_ts: candidateTs,
  final_text: finalText,
  found: !!botDraft
};

const candidates = ($('Extract Final Draft').first().json.candidate_ts || '').split(',').filter(Boolean);
const pages = $input.all().map(i => i.json);

const getTs = (p) => {
  if (p.property_slack_ts) return String(p.property_slack_ts).trim();
  const rt = p.properties && p.properties['Slack TS'] && p.properties['Slack TS'].rich_text;
  if (rt && rt.length) return rt.map(r => r.plain_text || '').join('').trim();
  return '';
};

let match = null;
for (const ts of candidates) {
  match = pages.find(p => getTs(p) === ts);
  if (match) break;
}

if (!match) return [];
return [{ json: match }];
